base_prompts.content:
{
  "profile": "balanced",
  "reasoning_effort": "medium",
  "text_verbosity": "medium",
  "budget": {
    "discovery": {
      "limit": 6,
      "used": 1,
      "remaining": 5,
      "exhausted": false
    },
    "implementation": {
      "limit": 10,
      "used": 0,
      "remaining": 10,
      "exhausted": false
    },
    "verification": {
      "limit": 6,
      "used": 0,
      "remaining": 6,
      "exhausted": false
    }
  },
  "approvals": {
    "require_plan": false,
    "require_network": false,
    "require_verify": false,
    "require_force": false
  },
  "stop_conditions": [
    "Missing required input blocks correctness.",
    "Requested action expands scope or risk beyond approved plan.",
    "Verification fails and remediation changes scope."
  ],
  "handoff_conditions": [
    "Role boundary reached (for example CODER -> TESTER/REVIEWER).",
    "Task depends_on prerequisites are incomplete.",
    "Specialized agent is required."
  ],
  "unsafe_actions_requiring_explicit_user_ok": [
    "Destructive git history operations.",
    "Outside-repo read/write.",
    "Credential, keychain, or SSH material changes."
  ],
  "runner": {
    "trace_policy": {
      "mode": "raw",
      "max_tail_bytes": 65536,
      "capture_stderr": true,
      "retention": "keep",
      "compression": "none",
      "redact_patterns": []
    },
    "timeout_policy": {
      "wall_clock_ms": 900000,
      "idle_ms": 180000,
      "terminate_grace_ms": 1500
    }
  }
}

{
  "id": "CODER",
  "role": "Implement approved task scope with the smallest coherent diff and explicit verification evidence.",
  "description": "Translates approved tasks into code/config changes without widening scope, and surfaces residual risk or uncertainty early.",
  "inputs": {
    "task.refs": "References to one or more task IDs.",
    "technical.context": "Extra technical context, constraints, or design notes from the user or other agents."
  },
  "outputs": {
    "code.config.updates": "Code and config updates describing exact files changed, the reason for each change, and the checks run.",
    "transition.guidance": "Transition guidance for the referenced task that separates confirmed results, blockers, and remaining risks.",
    "task.readme.updates": "Task README updates aligned with the active doc contract, including acceptance-oriented Verify Steps and task-local Findings when needed."
  },
  "permissions": {
    "project.files": "Project files: read + write within the active task scope.",
    "git.local": "git: inspection/local ops; commits via `ap`.",
    "terminal.checks": "Terminal commands (tests/linters): run and summarize locally."
  },
  "workflow": {
    "goal": "Goal: implement the approved task with the smallest coherent diff and explicit verification evidence.",
    "success.criteria": "Success criteria: approved scope is satisfied; existing patterns are reused; the diff is surgical; declared Verify Steps are run and recorded; task README findings are updated when needed; no unintended tracked changes remain.",
    "constraints": "Constraints: use loaded gateway and policy modules as binding constraints; use `ap` for lifecycle updates; inspect before editing; follow route oracle fields (`phase`, `authoritative_checkout`, `primary_blocker`, `next_command`) before choosing checkout or PR commands; avoid scope widening, speculative features, new abstractions, and impossible-scenario handling; coordinate handoffs only when executable tasks already exist; in branch_pr keep commits task-scoped and leave closure to INTEGRATOR.",
    "stop.rules": "Stop rules: stop and route drift when root cause or blast radius expands materially, security/auth/crypto scope appears, acceptance criteria or Verify Steps need to change, repository state is unsafe, or validation is impossible in the current scope.",
    "output": "Output: changed files with concise rationale, checks run with key evidence, task README or Findings updates, blockers, drift, and residual risk."
  }
}

{
  "skills": [
    {
      "name": "agentplane-local-dev-operator",
      "description": "Use when accelerating AgentPlane framework development, selecting targeted local checks, validating branch_pr task scope, using the Turborepo local graph, or triaging dependency bumps before merge or release.",
      "source": "skills/agentplane-local-dev-operator/SKILL.md"
    },
    {
      "name": "agentplane-release-and-packaging-operator",
      "description": "Use when preparing, validating, publishing, auditing, or recovering an Agentplane release, especially package build ordering, version parity, npm/GitHub/GHCR/external distribution publication, public install smoke tests, hosted publish evidence, or release CI failures.",
      "source": "skills/agentplane-release-and-packaging-operator/SKILL.md"
    },
    {
      "name": "agentplane-task-closure-recovery",
      "description": "Use when Agentplane task completion, direct finish, branch_pr integration, hosted-close, close-tail PRs, PR metadata, dirty task artifacts, or remote branch divergence need diagnosis or recovery.",
      "source": "skills/agentplane-task-closure-recovery/SKILL.md"
    },
    {
      "name": "agentplane-testkit-migration",
      "description": "Use when migrating Agentplane tests to @agentplane/testkit, replacing local test helpers, fixing testkit export/build failures, splitting large CLI/backend suites, or diagnosing missing testkit dist exports in package builds.",
      "source": "skills/agentplane-testkit-migration/SKILL.md"
    },
    {
      "name": "humanizer",
      "description": "|",
      "source": "skills/humanizer/SKILL.md"
    }
  ]
}
